const platforms = ['HackerRank', 'GeeksforGeeks', 'LeetCode', 'CodeChef', 'AtCoder', 'Codeforces'];
const difficulty = [4.8, 5.9, 7.6, 8.4, 9.1, 9.7];
const colors = [
  '#10b981', // Emerald
  '#3b82f6', // Blue
  '#f59e0b', // Amber
  '#ef4444', // Red
  '#8b5cf6', // Violet
  '#ec4899'  // Pink
];

return [{
  x: platforms,
  y: difficulty,
  type: 'bar',
  marker: {
    color: colors,
    line: {
      width: 2,
      color: '#1e293b'
    }
  },
  text: difficulty.map(v => v + ' / 10'),
  textposition: 'outside',
  cliponaxis: false,
  hovertemplate: '<b>%{x}</b><br>Difficulty: %{y}/10<extra></extra>'
}];
